import { PixelBuffer } from "./PixelBuffer.ts";
import { Palette } from "./Palette";
import { BaseTool } from "./Tools/BaseTool.ts";
import { StampTool } from "./Tools/StampTool.ts";
import { Vector2 } from "./Geometry.ts";
import { Toolbar } from "./Toolbar.ts";

export { Palette, PixelBuffer, StampTool }

const PICTOPUP_HTML = `
<canvas class="picto-drawsurface">
<div class="picto-toolbar"></div>
`;

/**
 * An instance of the Pictopup image editor
 */
export class Pictopup {
    /** Determines whether to redraw the screen post-input */
    isDirty: boolean;

    /**
     * Div frame holding the editor
     */
    frame: HTMLDivElement;

    /** Toolbar, holds tools */
    toolbar: Toolbar;

    /**
     * Image buffer containing committed pixel data
     */
    imageBuffer: PixelBuffer;

    /**
     * Image bitmap of last rendered image buffer
     */
    private imageBitmap?: ImageBitmap;

    /**
     * Back buffer to be drawn to the canvas every frame
     */
    private workBuffer: PixelBuffer;

    /**
     * Palette currently being used for output image
     */
    palette: Palette;

    private canvas: HTMLCanvasElement;
    private ctx: CanvasRenderingContext2D;

    /** Off-screen renderer */
    private workCanvas: HTMLCanvasElement;
    private workCtx: CanvasRenderingContext2D;

    /** Width of image */
    width: number;

    /** Height of image */
    height: number;

    /**
     * Creates a new instance of the Pictopup image editor
     * @param div Div to parent the editor to
     */
    constructor(div: HTMLDivElement, width: number, height: number) {
        // Build HTML
        this.frame = div;
        this.frame.innerHTML += PICTOPUP_HTML;

        // Create code objects
        this.palette = new Palette();
        this.toolbar = new Toolbar(this);

        this.isDirty = true; // do initial draw

        this.imageBuffer = new PixelBuffer(width, height);

        this.workBuffer = this.imageBuffer.clone();
        this.width = width;
        this.height = height;

        // Build HTML
        this.canvas = div.getElementsByClassName("picto-drawsurface")[0] as HTMLCanvasElement;
        this.canvas.width = width;
        this.canvas.height = height;

        this.workCanvas = document.createElement("canvas");
        this.workCanvas.width = width;
        this.workCanvas.height = height;

        this.ctx = this.canvas.getContext('2d') as CanvasRenderingContext2D;
        this.workCtx = this.workCanvas.getContext('2d') as CanvasRenderingContext2D;

        div.appendChild(this.canvas);

        // Setup events
        document.addEventListener("mousedown", this.processInputEvent.bind(this));
        document.addEventListener("mouseup", this.processInputEvent.bind(this));
        document.addEventListener("mousemove", this.processInputEvent.bind(this));
        document.addEventListener("mouseenter", this.processInputEvent.bind(this));
        document.addEventListener("mouseleave", this.processInputEvent.bind(this));
        document.addEventListener("wheel", this.processInputEvent.bind(this));
        document.addEventListener("keydown", this.processInputEvent.bind(this));
        document.addEventListener("keyup", this.processInputEvent.bind(this));

        // Setup render pipeline

        var picto = this;
        async function frame() {
            await picto.render();

            window.requestAnimationFrame(frame);
        }

        // Create render thread
        frame();
    }

    /**
     * Transforms screenspace coordinates into pixel coordinates on the canvas
     * @param mx Mouse position X in screen space
     * @param my Mouse position Y in screen space
     */
    ssToCanvasCoordinate(mx: number, my: number): Vector2 {
        var bounds: DOMRect = this.canvas.getBoundingClientRect();

        return Vector2.create(
            Math.floor((mx - bounds.x) * this.imageBuffer.width / bounds.width),
            Math.floor((my - bounds.y) * this.imageBuffer.height / bounds.height)
        );
    }

    /**
     * Processes input events such as mouse movement, clicks, keystrokes, etc.
     * 
     */
    async processInputEvent(event: Event) {
        // Do tool input
        if (this.toolbar.currentTool != undefined) {
            await this.toolbar.currentTool.processInputEvent(event);

            // Do not continue processing if the current tool is requiring all focus
            if (this.toolbar.currentTool.lockInput) return;
        }
    }

    /** Writes the image buffer to bitmap for drawing; needs to be replaced by history stack + Actions */
    async flush() {
        this.imageBitmap = await this.imageBuffer.rasterize(this.palette);
    }

    /**
     * Draws Pictopup and its tools to the canvas
     */
    async render() {
        /**
         * A lot of great optimizations could be done here
         * ...for instance: render out imagebitmap and only refresh edited pixels
         */
        // Do initial bitmap render if needed
        if (this.imageBitmap == undefined) {
            this.imageBitmap = await this.imageBuffer.rasterize(this.palette);
        }

        if (this.isDirty) {
            this.isDirty = false;

            // Draw image bitmap
            this.workCtx.drawImage(this.imageBitmap, 0, 0);

            // Draw current tool if being used
            if (this.toolbar.currentTool != undefined) {
                await this.toolbar.currentTool.render(this.workCtx);
            }
            
            // // Flip work buffer to screen
            this.ctx.drawImage(this.workCanvas, 0, 0);
        }
    }
}
