import { Pictopup, StampTool } from "./Pictopup";
import { BaseTool } from "./Tools/BaseTool";

export class Toolbar {
    picto: Pictopup;
    currentTool?: BaseTool;

    /** Stamp tool */
    stampTool: StampTool;

    constructor(picto: Pictopup) {
        this.picto = picto;
        this.stampTool = new StampTool(picto);
        
        // Current tool
        this.currentTool = this.stampTool;
    }
}